    "Cross-device editing": "\u0e41\u0e01\u0e49\u0e44\u0e02\u0e02\u0e49\u0e32\u0e21\u0e2d\u0e38\u0e1b\u0e01\u0e23\u0e13\u0e4c",
    "DOCUMENT TEMPLATES": "\u0e40\u0e17\u0e21\u0e40\u0e1e\u0e25\u0e15\u0e40\u0e2d\u0e01\u0e2a\u0e32\u0e23",
    "Daily limit: 3 free conversions": "\u0e08\u0e33\u0e01\u0e31\u0e14\u0e23\u0e32\u0e22\u0e27\u0e31\u0e19: \u0e41\u0e1b\u0e25\u0e07\u0e1f\u0e23\u0e35 3 \u0e04\u0e23\u0e31\u0e49\u0e07",
    "Data & Formulas": "\u0e02\u0e49\u0e2d\u0e21\u0e39\u0e25\u0e41\u0e25\u0e30\u0e2a\u0e39\u0e15\u0e23",
    "Data Analysis": "Data Analysis",
    "Data Collection": "\u0e01\u0e32\u0e23\u0e40\u0e01\u0e47\u0e1a\u0e02\u0e49\u0e2d\u0e21\u0e39\u0e25",
    "Data analysis suggestions": "\u0e04\u0e33\u0e41\u0e19\u0e30\u0e19\u0e33\u0e01\u0e32\u0e23\u0e27\u0e34\u0e40\u0e04\u0e23\u0e32\u0e30\u0e2b\u0e4c\u0e02\u0e49\u0e2d\u0e21\u0e39\u0e25",
    "Data import and cleanup": "\u0e01\u0e32\u0e23\u0e19\u0e33\u0e40\u0e02\u0e49\u0e32\u0e02\u0e49\u0e2d\u0e21\u0e39\u0e25\u0e41\u0e25\u0e30\u0e17\u0e33\u0e04\u0e27\u0e32\u0e21\u0e2a\u0e30\u0e2d\u0e32\u0e14\u0e02\u0e49\u0e2d\u0e21\u0e39\u0e25",
    "Describe the outcome you want in plain language; WPS Sheets proposes a formula with a short explanation.": "\u0e2d\u0e18\u0e34\u0e1a\u0e32\u0e22\u0e1c\u0e25\u0e25\u0e31\u0e1e\u0e18\u0e4c\u0e17\u0e35\u0e48\u0e04\u0e38\u0e13\u0e15\u0e49\u0e2d\u0e07\u0e01\u0e32\u0e23\u0e14\u0e49\u0e27\u0e22\u0e20\u0e32\u0e29\u0e32\u0e18\u0e23\u0e23\u0e21\u0e14\u0e32 \u0e41\u0e25\u0e49\u0e27 WPS Sheets \u0e08\u0e30\u0e40\u0e2a\u0e19\u0e2d\u0e2a\u0e39\u0e15\u0e23\u0e1e\u0e23\u0e49\u0e2d\u0e21\u0e04\u0e33\u0e2d\u0e18\u0e34\u0e1a\u0e32\u0e22\u0e2a\u0e31\u0e49\u0e19\u0e46",
    "Describe what you want to write...": "\u0e2d\u0e18\u0e34\u0e1a\u0e32\u0e22\u0e2a\u0e34\u0e48\u0e07\u0e17\u0e35\u0e48\u0e04\u0e38\u0e13\u0e15\u0e49\u0e2d\u0e07\u0e01\u0e32\u0e23\u0e40\u0e02\u0e35\u0e22\u0e19...",
    "Desktop Client": "\u0e44\u0e04\u0e25\u0e40\u0e2d\u0e19\u0e15\u0e4c\u0e40\u0e14\u0e2a\u0e01\u0e4c\u0e17\u0e47\u0e2d\u0e1b",
    "Developer": "\u0e19\u0e31\u0e01\u0e1e\u0e31\u0e12\u0e19\u0e32",
    "Discover how to use AI Writer to create blog posts, emails, and more in minutes.": "\u0e40\u0e23\u0e35\u0e22\u0e19\u0e23\u0e39\u0e49\u0e27\u0e34\u0e18\u0e35\u0e43\u0e0a\u0e49 AI Writer \u0e40\u0e1e\u0e37\u0e48\u0e2d\u0e2a\u0e23\u0e49\u0e32\u0e07\u0e1a\u0e17\u0e04\u0e27\u0e32\u0e21\u0e1a\u0e25\u0e47\u0e2d\u0e01 \u0e2d\u0e35\u0e40\u0e21\u0e25 \u0e41\u0e25\u0e30\u0e2d\u0e37\u0e48\u0e19\u0e46 \u0e44\u0e14\u0e49\u0e20\u0e32\u0e22\u0e43\u0e19\u0e44\u0e21\u0e48\u0e01\u0e35\u0e48\u0e19\u0e32\u0e17\u0e35",
    "Discuss learning paths, certifications, and skill-building resources.": "\u0e1e\u0e39\u0e14\u0e04\u0e38\u0e22\u0e40\u0e01\u0e35\u0e48\u0e22\u0e27\u0e01\u0e31\u0e1a\u0e40\u0e2a\u0e49\u0e19\u0e17\u0e32\u0e07\u0e01\u0e32\u0e23\u0e40\u0e23\u0e35\u0e22\u0e19\u0e23\u0e39\u0e49 \u0e01\u0e32\u0e23\u0e23\u0e31\u0e1a\u0e23\u0e2d\u0e07 \u0e41\u0e25\u0e30\u0e17\u0e23\u0e31\u0e1e\u0e22\u0e32\u0e01\u0e23\u0e40\u0e1e\u0e37\u0e48\u0e2d\u0e1e\u0e31\u0e12\u0e19\u0e32\u0e17\u0e31\u0e01\u0e29\u0e30",
    "Document Editing": "\u0e01\u0e32\u0e23\u0e41\u0e01\u0e49\u0e44\u0e02\u0e40\u0e2d\u0e01\u0e2a\u0e32\u0e23",
    "Document summarization": "\u0e01\u0e32\u0e23\u0e2a\u0e23\u0e38\u0e1b\u0e40\u0e2d\u0e01\u0e2a\u0e32\u0e23",
    "Document utilities": "\u0e40\u0e04\u0e23\u0e37\u0e48\u0e2d\u0e07\u0e21\u0e37\u0e2d\u0e40\u0e2d\u0e01\u0e2a\u0e32\u0e23",
    "Download for Linux": "\u0e14\u0e32\u0e27\u0e19\u0e4c\u0e42\u0e2b\u0e25\u0e14\u0e2a\u0e33\u0e2b\u0e23\u0e31\u0e1a Linux",
    "Download for Mac": "\u0e14\u0e32\u0e27\u0e19\u0e4c\u0e42\u0e2b\u0e25\u0e14\u0e2a\u0e33\u0e2b\u0e23\u0e31\u0e1a Mac",
    "Download for Windows": "\u0e14\u0e32\u0e27\u0e19\u0e4c\u0e42\u0e2b\u0e25\u0e14\u0e2a\u0e33\u0e2b\u0e23\u0e31\u0e1a Windows",
    "Download the PDF from the Trust Center or request a briefing for your security team.": "\u0e14\u0e32\u0e27\u0e19\u0e4c\u0e42\u0e2b\u0e25\u0e14 PDF \u0e08\u0e32\u0e01 Trust Center \u0e2b\u0e23\u0e37\u0e2d\u0e02\u0e2d\u0e01\u0e32\u0e23\u0e1a\u0e23\u0e23\u0e22\u0e32\u0e22\u0e2a\u0e23\u0e38\u0e1b\u0e43\u0e2b\u0e49\u0e17\u0e35\u0e21\u0e04\u0e27\u0e32\u0e21\u0e1b\u0e25\u0e2d\u0e14\u0e20\u0e31\u0e22\u0e02\u0e2d\u0e07\u0e04\u0e38\u0e13",
    "East Asia": "\u0e40\u0e2d\u0e40\u0e0a\u0e35\u0e22\u0e15\u0e30\u0e27\u0e31\u0e19\u0e2d\u0e2d\u0e01",
    "Edit PDF": "Edit PDF",
    "Edit Word, Excel, and PDF files on the go with full cloud sync.": "\u0e41\u0e01\u0e49\u0e44\u0e02\u0e44\u0e1f\u0e25\u0e4c Word, Excel \u0e41\u0e25\u0e30 PDF \u0e44\u0e14\u0e49\u0e17\u0e38\u0e01\u0e17\u0e35\u0e48\u0e1e\u0e23\u0e49\u0e2d\u0e21\u0e01\u0e32\u0e23\u0e0b\u0e34\u0e07\u0e04\u0e4c\u0e04\u0e25\u0e32\u0e27\u0e14\u0e4c\u0e40\u0e15\u0e47\u0e21\u0e23\u0e39\u0e1b\u0e41\u0e1a\u0e1a",
    "Email Writer": "Email Writer",
    "Encryption, data residency, and admin controls for regulated industries.": "\u0e01\u0e32\u0e23\u0e40\u0e02\u0e49\u0e32\u0e23\u0e2b\u0e31\u0e2a \u0e01\u0e32\u0e23\u0e40\u0e01\u0e47\u0e1a\u0e02\u0e49\u0e2d\u0e21\u0e39\u0e25\u0e15\u0e32\u0e21\u0e1e\u0e37\u0e49\u0e19\u0e17\u0e35\u0e48 \u0e41\u0e25\u0e30\u0e01\u0e32\u0e23\u0e04\u0e27\u0e1a\u0e04\u0e38\u0e21\u0e02\u0e2d\u0e07\u0e1c\u0e39\u0e49\u0e14\u0e39\u0e41\u0e25\u0e2a\u0e33\u0e2b\u0e23\u0e31\u0e1a\u0e2d\u0e38\u0e15\u0e2a\u0e32\u0e2b\u0e01\u0e23\u0e23\u0e21\u0e17\u0e35\u0e48\u0e21\u0e35\u0e02\u0e49\u0e2d\u0e01\u0e33\u0e01\u0e31\u0e1a\u0e14\u0e39\u0e41\u0e25",
    "English": "\u0e20\u0e32\u0e29\u0e32\u0e2d\u0e31\u0e07\u0e01\u0e24\u0e29",
    "Essay Writer": "Essay Writer",
    "Every tool enhanced with cutting-edge AI for smarter results.": "\u0e17\u0e38\u0e01\u0e40\u0e04\u0e23\u0e37\u0e48\u0e2d\u0e07\u0e21\u0e37\u0e2d\u0e40\u0e2a\u0e23\u0e34\u0e21\u0e14\u0e49\u0e27\u0e22 AI \u0e25\u0e49\u0e33\u0e2a\u0e21\u0e31\u0e22\u0e40\u0e1e\u0e37\u0e48\u0e2d\u0e1c\u0e25\u0e25\u0e31\u0e1e\u0e18\u0e4c\u0e17\u0e35\u0e48\u0e0a\u0e32\u0e0d\u0e09\u0e25\u0e32\u0e14\u0e22\u0e34\u0e48\u0e07\u0e02\u0e36\u0e49\u0e19",
    "Everything in Pro": "\u0e17\u0e38\u0e01\u0e2d\u0e22\u0e48\u0e32\u0e07\u0e43\u0e19 Pro",
    "Everything you need to know about combining and splitting PDF files for better document management.": "\u0e17\u0e38\u0e01\u0e2a\u0e34\u0e48\u0e07\u0e17\u0e35\u0e48\u0e04\u0e38\u0e13\u0e15\u0e49\u0e2d\u0e07\u0e23\u0e39\u0e49\u0e40\u0e01\u0e35\u0e48\u0e22\u0e27\u0e01\u0e31\u0e1a\u0e01\u0e32\u0e23\u0e23\u0e27\u0e21\u0e41\u0e25\u0e30\u0e41\u0e22\u0e01\u0e44\u0e1f\u0e25\u0e4c PDF \u0e40\u0e1e\u0e37\u0e48\u0e2d\u0e01\u0e32\u0e23\u0e08\u0e31\u0e14\u0e01\u0e32\u0e23\u0e40\u0e2d\u0e01\u0e2a\u0e32\u0e23\u0e17\u0e35\u0e48\u0e14\u0e35\u0e02\u0e36\u0e49\u0e19",
    "Excel Templates": "\u0e40\u0e17\u0e21\u0e40\u0e1e\u0e25\u0e15 Excel",
    "Excel to PDF": "Excel \u0e40\u0e1b\u0e47\u0e19 PDF",
    "Exchange ideas for business, education, and personal template design.": "\u0e41\u0e25\u0e01\u0e40\u0e1b\u0e25\u0e35\u0e48\u0e22\u0e19\u0e44\u0e2d\u0e40\u0e14\u0e35\u0e22\u0e40\u0e01\u0e35\u0e48\u0e22\u0e27\u0e01\u0e31\u0e1a\u0e01\u0e32\u0e23\u0e2d\u0e2d\u0e01\u0e41\u0e1a\u0e1a\u0e40\u0e17\u0e21\u0e40\u0e1e\u0e25\u0e15\u0e2a\u0e33\u0e2b\u0e23\u0e31\u0e1a\u0e18\u0e38\u0e23\u0e01\u0e34\u0e08 \u0e01\u0e32\u0e23\u0e28\u0e36\u0e01\u0e29\u0e32 \u0e41\u0e25\u0e30\u0e01\u0e32\u0e23\u0e43\u0e0a\u0e49\u0e07\u0e32\u0e19\u0e2a\u0e48\u0e27\u0e19\u0e15\u0e31\u0e27",
    "Export and printing": "\u0e01\u0e32\u0e23\u0e2a\u0e48\u0e07\u0e2d\u0e2d\u0e01\u0e41\u0e25\u0e30\u0e01\u0e32\u0e23\u0e1e\u0e34\u0e21\u0e1e\u0e4c",
    "Export and sharing": "\u0e01\u0e32\u0e23\u0e2a\u0e48\u0e07\u0e2d\u0e2d\u0e01\u0e41\u0e25\u0e30\u0e01\u0e32\u0e23\u0e41\u0e0a\u0e23\u0e4c",
    "Export responses to sheets": "\u0e2a\u0e48\u0e07\u0e2d\u0e2d\u0e01\u0e04\u0e33\u0e15\u0e2d\u0e1a\u0e44\u0e1b\u0e22\u0e31\u0e07\u0e0a\u0e35\u0e15",
    "Export to video and PDF": "\u0e2a\u0e48\u0e07\u0e2d\u0e2d\u0e01\u0e40\u0e1b\u0e47\u0e19\u0e27\u0e34\u0e14\u0e35\u0e42\u0e2d\u0e41\u0e25\u0e30 PDF",
    "Extended (1000+ words)": "\u0e41\u0e1a\u0e1a\u0e22\u0e32\u0e27\u0e21\u0e32\u0e01 (1000+ \u0e04\u0e33)",
